import React, { useState } from "react";
import axios from "axios";
import { Line } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler,
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler
);

const IndianStockDetails = () => {
  const [symbol, setSymbol] = useState("");
  const [data, setData] = useState(null);
  const [error, setError] = useState("");

  const fetchStockData = async () => {
    setError("");
    setData(null);
    try {
      const res = await axios.get(`/api/stocks/${symbol}`);
      setData(res.data);
    } catch (err) {
      setError("Failed to fetch stock data");
      console.error(err);
    }
  };

  const renderChart = () => {
    if (!data?.historical?.length) return null;

    const labels = data.historical.map((item) =>
      new Date(item.date).toLocaleDateString("en-IN", { month: "short", day: "numeric" })
    );

    const prices = data.historical.map((item) => item.close);

    return (
      <Line
        data={{
          labels,
          datasets: [
            {
              label: `${data.symbol} Closing Price`,
              data: prices,
              borderColor: "blue",
              backgroundColor: "rgba(0, 123, 255, 0.2)",
              tension: 0.3,
              fill: true,
            },
          ],
        }}
        options={{
          responsive: true,
          plugins: {
            legend: {
              display: false,
            },
            title: {
              display: true,
              text: "Stock Price (Last Few Months)",
              font: { size: 18 },
            },
          },
        }}
      />
    );
  };

  const renderMetric = (label, value, isCurrency = false) => {
    return (
      <li>
        <strong>{label}:</strong>{" "}
        {value
          ? isCurrency
            ? `₹${Number(value).toLocaleString()}`
            : value
          : "N/A"}
      </li>
    );
  };

  return (
    <div style={{ padding: "20px", fontFamily: "Arial" }}>
      <h2>📊 Indian Stock Insights</h2>

      <input
        type="text"
        placeholder="Enter Stock Symbol (e.g., TCS)"
        value={symbol}
        onChange={(e) => setSymbol(e.target.value)}
        style={{ padding: "8px", width: "250px" }}
      />
      <button onClick={fetchStockData} style={{ padding: "8px 12px", marginLeft: "10px" }}>
        Fetch
      </button>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {data && (
        <div style={{ marginTop: "30px" }}>
          <h3>
            {data.name} ({data.symbol})
          </h3>
          <h1 style={{ color: data.change > 0 ? "green" : "red" }}>
            ₹{data.price?.toFixed(2)}{" "}
            <small>
              (Change: {data.change?.toFixed(2)} | {data.percentChange?.toFixed(2)}%)
            </small>
          </h1>

          <h4>📌 Fundamentals</h4>
          <ul>
            {renderMetric("Market Capitalization", data.marketCap, true)}
            {renderMetric("P/E Ratio (TTM)", data.peRatio)}
            {renderMetric("Dividend Yield (%)", data.dividendYield)}
            {renderMetric("52 Week High", data.fiftyTwoWeekHigh, true)}
            {renderMetric("52 Week Low", data.fiftyTwoWeekLow, true)}
          </ul>

          <div style={{ marginTop: "40px" }}>{renderChart()}</div>
        </div>
      )}
    </div>
  );
};

export default IndianStockDetails;
